  {{% if product in ['rhel10', 'ol10']  %}}
    /usr/lib/systemd/system/audit-rules.service
    ^ExecStart=(\/usr|)?\/sbin\/augenrules.*$
  {{% elif product in ['fedora'] %}}
    /usr/lib/systemd/system/audit-rules.service
    ^ExecStart=\/usr\/bin\/augenrules.*$
