    /usr/lib/systemd/system/audit-rules.service
    ^ExecStart=\/usr\/sbin\/augenrules.*$
  {{% else %}}
    /usr/lib/systemd/system/auditd.service
    ^(ExecStartPost=\-\/sbin\/augenrules.*$|Requires=augenrules.service)
  {{% endif %}}
